            j=j*2;
            a++;
        }
        else
        {
            s2=s2+t;
        }
    }
    j=1;
    a=1;
    for(i=1;i<=n;i++)
    {
        if(a<=(n-l+1))
        {
            s1=s1+1;
            a++;
        }
        else
        {
            j=j*2;
