#![allow(warnings)]

use std::io::{self, *};
use std::str::{self, *};

fn main() {
    let mut stdin = stdin();
    let mut buffer = String::new();
    let _ = stdin.read_to_string(&mut buffer);
    let mut input = buffer.split_whitespace().map(|w| w.parse::<i32>().unwrap());
    let n = input.next().unwrap();
    let l = input.next().unwrap();
    let r = input.next().unwrap();

    let mini = (0..l).map(|i| 2_i32.pow(i as u32)).sum::<i32>() + (n - l);
    let maxi = (0..r).map(|i| 2_i32.pow(i as u32)).sum::<i32>() + (n - r) * 2_i32.pow((r-1) as u32);

    println!("{} {}", mini, maxi);
}
